import { useState, useEffect, useCallback } from "react";
import { useSearchParams, useNavigate } from "react-router-dom";
import MapView from "../components/MapView";
import api from "../utils/api";

const CATS = [
  { key: "all", label: "Бүгд", icon: "🗺" },
  { key: "hairsalon", label: "Үсчин", icon: "✂" },
  { key: "beauty", label: "Гоо сайхан", icon: "💄" },
  { key: "billiard", label: "Бильярд", icon: "🎱" },
  { key: "cafe", label: "Кафе", icon: "☕" },
  { key: "fitness", label: "Фитнесс", icon: "💪" },
];

export default function HomePage() {
  const [params, setParams] = useSearchParams();
  const [businesses, setBiz] = useState([]);
  const [loading, setLoading] = useState(true);
  const [userPos, setUserPos] = useState(null);
  const [mapCenter, setCenter] = useState(null);
  const [radius, setRadius] = useState(5);
  const [search, setSearch] = useState("");
  const nav = useNavigate();
  const cat = params.get("category") || "all";

  // Байгууллага татах
  const load = useCallback(async () => {
    setLoading(true);
    try {
      let url = "/businesses";
      const q = new URLSearchParams();
      if (cat !== "all") q.set("category", cat);
      if (search) q.set("search", search);
      if (q.toString()) url += "?" + q;
      const { data } = await api.get(url);
      setBiz(data.data);
    } catch {
      setBiz([]);
    }
    setLoading(false);
  }, [cat, search]);

  useEffect(() => {
    load();
  }, [load]);

  // Байршил авах
  const getLocation = () => {
    navigator.geolocation?.getCurrentPosition(async (pos) => {
      const { latitude: lat, longitude: lng } = pos.coords;
      setUserPos([lat, lng]);
      setCenter([lat, lng]);
      try {
        const { data } = await api.get(
          `/businesses/nearby?lat=${lat}&lng=${lng}&radius=${radius}`,
        );
        setBiz(data.data);
      } catch {}
    });
  };

  useEffect(() => {
    getLocation();
  }, []); // eslint-disable-line

  const setCat = (k) => {
    const p = new URLSearchParams(params);
    if (k === "all") p.delete("category");
    else p.set("category", k);
    setParams(p);
  };

  return (
    <div
      style={{
        height: "calc(100vh - 56px)",
        display: "flex",
        flexDirection: "column",
      }}
    >
      {/* Category pills */}
      <div
        style={{
          padding: "10px 20px",
          background: "var(--bg)",
          borderBottom: "1px solid var(--border)",
          display: "flex",
          gap: 8,
          alignItems: "center",
          overflowX: "auto",
        }}
      >
        {CATS.map((c) => (
          <button
            key={c.key}
            onClick={() => setCat(c.key)}
            style={{
              padding: "6px 16px",
              borderRadius: 20,
              fontSize: 13,
              fontWeight: 500,
              cursor: "pointer",
              border: "1px solid",
              whiteSpace: "nowrap",
              background: cat === c.key ? "var(--teal)" : "var(--card)",
              color: cat === c.key ? "#fff" : "var(--muted)",
              borderColor: cat === c.key ? "var(--teal)" : "var(--border)",
              transition: "all .15s",
            }}
          >
            {c.icon} {c.label}
          </button>
        ))}
        <div
          style={{
            marginLeft: "auto",
            display: "flex",
            gap: 8,
            alignItems: "center",
          }}
        >
          <input
            placeholder="Хайх..."
            value={search}
            onChange={(e) => setSearch(e.target.value)}
            style={{
              padding: "6px 12px",
              background: "var(--card)",
              border: "1px solid var(--border)",
              borderRadius: 8,
              color: "var(--text)",
              fontSize: 13,
              width: 180,
            }}
          />
          <button
            onClick={getLocation}
            style={{
              padding: "6px 14px",
              background: "var(--blue)",
              color: "#fff",
              border: "none",
              borderRadius: 8,
              cursor: "pointer",
              fontSize: 13,
              whiteSpace: "nowrap",
            }}
          >
            📍 Байршил
          </button>
        </div>
      </div>

      {/* Map + list */}
      <div style={{ flex: 1, display: "flex", overflow: "hidden" }}>
        {/* Map */}
        <div style={{ flex: 1, position: "relative" }}>
          <MapView
            businesses={businesses}
            userPos={userPos}
            center={mapCenter}
          />
        </div>

        {/* Side list */}
        <div
          style={{
            width: 380,
            overflowY: "auto",
            borderLeft: "1px solid var(--border)",
            background: "var(--bg)",
          }}
        >
          <div
            style={{
              padding: "16px 16px 8px",
              fontSize: 13,
              color: "var(--muted)",
            }}
          >
            {loading
              ? "Ачаалж байна..."
              : `Ойрхон газрууд — ${businesses.length} олдлоо`}
          </div>
          {businesses.map((b) => (
            <div
              key={b._id}
              onClick={() => nav(`/business/${b._id}`)}
              style={{
                margin: "0 10px 10px",
                borderRadius: 12,
                overflow: "hidden",
                background: "var(--card)",
                border: "1px solid var(--border)",
                cursor: "pointer",
                transition: "border-color .15s",
              }}
              onMouseEnter={(e) =>
                (e.currentTarget.style.borderColor = "var(--blue)")
              }
              onMouseLeave={(e) =>
                (e.currentTarget.style.borderColor = "var(--border)")
              }
            >
              {/* Image */}
              <div
                style={{
                  height: 120,
                  overflow: "hidden",
                  background: "#1C2128",
                }}
              >
                {b.images?.[0] ? (
                  <img
                    src={b.images[0]}
                    alt={b.name}
                    style={{
                      width: "100%",
                      height: "100%",
                      objectFit: "cover",
                    }}
                  />
                ) : (
                  <div
                    style={{
                      height: "100%",
                      display: "flex",
                      alignItems: "center",
                      justifyContent: "center",
                      fontSize: 36,
                      color: "var(--muted)",
                    }}
                  >
                    {CATS.find((c) => c.key === b.category)?.icon || "📍"}
                  </div>
                )}
              </div>
              {/* Info */}
              <div style={{ padding: "10px 12px" }}>
                <div
                  style={{
                    display: "flex",
                    justifyContent: "space-between",
                    alignItems: "flex-start",
                  }}
                >
                  <div style={{ fontWeight: 600, fontSize: 14 }}>{b.name}</div>
                  <div
                    style={{
                      display: "flex",
                      alignItems: "center",
                      gap: 3,
                      fontSize: 12,
                    }}
                  >
                    <span style={{ color: "#F59E0B" }}>⭐</span>
                    <span style={{ fontWeight: 600 }}>{b.rating}</span>
                  </div>
                </div>
                <div
                  style={{ fontSize: 12, color: "var(--muted)", marginTop: 3 }}
                >
                  {b.address}
                </div>
                <div
                  style={{
                    display: "flex",
                    gap: 8,
                    marginTop: 8,
                    alignItems: "center",
                  }}
                >
                  {b.distance != null && (
                    <span style={{ fontSize: 12, color: "#60A5FA" }}>
                      📍 {b.distance}км
                    </span>
                  )}
                  <span
                    style={{
                      fontSize: 11,
                      padding: "2px 8px",
                      borderRadius: 10,
                      background: "rgba(13,148,136,0.15)",
                      color: "var(--teal)",
                    }}
                  >
                    {CATS.find((c) => c.key === b.category)?.label || "Бусад"}
                  </span>
                  <span
                    style={{
                      marginLeft: "auto",
                      fontSize: 12,
                      color: b.isActive ? "var(--green)" : "var(--red)",
                    }}
                  >
                    {b.isActive ? "● Нээлттэй" : "● Хаалттай"}
                  </span>
                </div>
              </div>
            </div>
          ))}
        </div>
      </div>
    </div>
  );
}
